example:
A Playwright + TypeScript Page Object and a test that uses it:

```typescript
// pages/LoginPage.ts
import { Page, Locator } from '@playwright/test';

export class LoginPage {
  readonly page: Page;
  readonly username: Locator;
  readonly password: Locator;
  readonly submit: Locator;
  readonly error: Locator;

  constructor(page: Page) {
    this.page = page;
    this.username = page.getByTestId('username');
    this.password = page.getByTestId('password');
    this.submit = page.getByRole('button', { name: 'Log in' });
    this.error = page.getByRole('alert');
  }

  async goto() {
    await this.page.goto('/login');
  }

  async loginAs(user: string, pass: string) {
    await this.username.fill(user);
    await this.password.fill(pass);
    await this.submit.click();
  }
}
```

```typescript
// tests/login.spec.ts
import { test, expect } from '@playwright/test';
import { LoginPage } from '../pages/LoginPage';

test('valid login lands on dashboard', async ({ page }) => {
  const login = new LoginPage(page);
  await login.goto();
  await login.loginAs('standard_user', 'secret_sauce');
  await expect(page).toHaveURL(/.*dashboard/);
});

test('invalid login shows error', async ({ page }) => {
  const login = new LoginPage(page);
  await login.goto();
  await login.loginAs('standard_user', 'wrong');
  await expect(login.error).toContainText('do not match');
});
```

