example:
Playwright API tests plus an API-driven fixture for UI setup (TypeScript):

```typescript
import { test, expect, request } from '@playwright/test';

// Pure API test using the built-in request fixture
test('GET product returns 200 and valid body', async ({ request }) => {
  const res = await request.get('/api/products/42');
  await expect(res).toBeOK();              // passes for any 2xx
  expect(res.status()).toBe(200);
  const body = await res.json();
  expect(typeof body.id).toBe('string');
  expect(body.price).toBeGreaterThanOrEqual(0);
});

test('POST without auth is rejected with 401', async ({ request }) => {
  const res = await request.post('/api/products', { data: { name: 'x', price: 1 } });
  expect(res.status()).toBe(401);
});
```

```typescript
// fixtures.ts - create state via API, hand it to a UI test, clean up after
import { test as base, expect } from '@playwright/test';

type Fixtures = { articleId: string };

export const test = base.extend<Fixtures>({
  articleId: async ({ request }, use) => {
    const create = await request.post('/api/articles', {
      data: { title: 'Draft', body: 'seeded via API' },
      headers: { Authorization: `Bearer ${process.env.TOKEN}` },
    });
    expect(create.ok()).toBeTruthy();
    const { id } = await create.json();
    await use(id);                          // test runs here
    await request.delete(`/api/articles/${id}`, {
      headers: { Authorization: `Bearer ${process.env.TOKEN}` },
    });                                     // teardown
  },
});
export { expect };
```
